#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding neurology-assessment (15 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    occupation:string! \
    ethnicity:string! \
    handedness:string! \
    contact_phone:string! \
    contact_email:string! \
    emergency_contact_name:string! \
    emergency_contact_phone:string! \
    gp_name:string! \
    gp_practice:string! \
    --htmx

cargo loco generate scaffold assessment_chief_complaint \
    assessment:references \
    chief_complaint:text! \
    symptom_onset_date:date \
    symptom_onset_time:string! \
    onset_type:string! \
    symptom_duration:string! \
    symptom_laterality:string! \
    headache:string! \
    weakness:string! \
    numbness:string! \
    speech_difficulty:string! \
    vision_changes:string! \
    dizziness:string! \
    seizure:string! \
    loss_of_consciousness:string! \
    previous_neurological_history:text! \
    chief_complaint_notes:text! \
    --htmx

cargo loco generate scaffold assessment_nihss \
    assessment:references \
    q1a_level_of_consciousness:int \
    q1b_loc_questions:int \
    q1c_loc_commands:int \
    q2_best_gaze:int \
    q3_visual_fields:int \
    q4_facial_palsy:int \
    q5a_motor_left_arm:int \
    q5b_motor_right_arm:int \
    q6a_motor_left_leg:int \
    q6b_motor_right_leg:int \
    q7_limb_ataxia:int \
    q8_sensory:int \
    q9_best_language:int \
    q10_dysarthria:int \
    q11_extinction_inattention:int \
    nihss_total_score:int \
    assessment_datetime:ts \
    nihss_notes:text! \
    --htmx

cargo loco generate scaffold assessment_headache \
    assessment:references \
    headache_present:string! \
    headache_type:string! \
    headache_severity:int \
    headache_location:string! \
    headache_side:string! \
    headache_frequency:string! \
    headache_duration:string! \
    aura:string! \
    aura_type:text! \
    photophobia:string! \
    phonophobia:string! \
    nausea_with_headache:string! \
    neck_stiffness:string! \
    worst_headache_ever:string! \
    headache_triggers:text! \
    headache_notes:text! \
    --htmx

cargo loco generate scaffold assessment_seizure_history \
    assessment:references \
    seizure_history:string! \
    epilepsy_diagnosis:string! \
    seizure_type:string! \
    seizure_frequency:string! \
    last_seizure_date:date \
    seizure_duration_typical:string! \
    seizure_triggers:text! \
    aura_before_seizure:string! \
    aura_description:text! \
    postictal_symptoms:text! \
    status_epilepticus_history:string! \
    febrile_seizures_childhood:string! \
    family_history_epilepsy:string! \
    driving_status:string! \
    seizure_notes:text! \
    --htmx

cargo loco generate scaffold assessment_motor_and_sensory_exam \
    assessment:references \
    upper_limb_power_left:int \
    upper_limb_power_right:int \
    lower_limb_power_left:int \
    lower_limb_power_right:int \
    grip_strength_left:int \
    grip_strength_right:int \
    upper_limb_tone_left:string! \
    upper_limb_tone_right:string! \
    lower_limb_tone_left:string! \
    lower_limb_tone_right:string! \
    biceps_reflex_left:int \
    biceps_reflex_right:int \
    knee_reflex_left:int \
    knee_reflex_right:int \
    ankle_reflex_left:int \
    ankle_reflex_right:int \
    plantar_response_left:string! \
    plantar_response_right:string! \
    light_touch_intact:string! \
    light_touch_deficit_area:text! \
    pinprick_intact:string! \
    pinprick_deficit_area:text! \
    proprioception_intact:string! \
    vibration_sense_intact:string! \
    finger_nose_test_left:string! \
    finger_nose_test_right:string! \
    heel_shin_test_left:string! \
    heel_shin_test_right:string! \
    romberg_test:string! \
    motor_sensory_notes:text! \
    --htmx

cargo loco generate scaffold assessment_cognitive \
    assessment:references \
    cognitive_complaint:string! \
    cognitive_complaint_details:text! \
    orientation_person:string! \
    orientation_place:string! \
    orientation_time:string! \
    attention_intact:string! \
    memory_immediate:string! \
    memory_delayed:string! \
    language_fluency:string! \
    naming:string! \
    comprehension:string! \
    repetition:string! \
    reading:string! \
    writing:string! \
    visuospatial:string! \
    executive_function:string! \
    mmse_score:int \
    moca_score:int \
    cognitive_notes:text! \
    --htmx

cargo loco generate scaffold assessment_current_medications \
    assessment:references \
    taking_neurological_medication:string! \
    anticonvulsants:string! \
    anticonvulsant_details:text! \
    anticoagulants:string! \
    anticoagulant_name:string! \
    antiplatelets:string! \
    antiplatelet_name:string! \
    analgesics:text! \
    triptans:string! \
    migraine_prophylaxis:text! \
    antihypertensives:string! \
    statins:string! \
    other_medications:text! \
    medication_adherence:string! \
    medication_notes:text! \
    --htmx

cargo loco generate scaffold assessment_diagnostic_results \
    assessment:references \
    ct_head:string! \
    ct_head_date:date \
    ct_head_result:text! \
    mri_brain:string! \
    mri_brain_date:date \
    mri_brain_result:text! \
    ct_angiography:string! \
    ct_angiography_result:text! \
    mr_angiography:string! \
    mr_angiography_result:text! \
    eeg:string! \
    eeg_date:date \
    eeg_result:text! \
    emg_nerve_conduction:string! \
    emg_result:text! \
    lumbar_puncture:string! \
    lumbar_puncture_result:text! \
    carotid_doppler:string! \
    carotid_doppler_result:text! \
    blood_tests_relevant:text! \
    diagnostic_notes:text! \
    --htmx

cargo loco generate scaffold assessment_functional_and_social \
    assessment:references \
    modified_rankin_score:int \
    barthel_index:int \
    daily_functioning:string! \
    employment_status:string! \
    driving_status:string! \
    mobility_level:string! \
    social_support:string! \
    carer_support:string! \
    carer_details:text! \
    mood_impact:string! \
    quality_of_life_score:int \
    rehabilitation_needs:text! \
    functional_social_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    nihss_total_score:int! \
    nihss_severity:string! \
    modified_rankin_score:int \
    barthel_index:int \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
